def test_lr_scheduler_combo(warmup, total, lr, seed):
    torch.manual_seed(seed)
    from distributed_training import LearningRateWarmupScheduler
    model = nn.Linear(4, 2)
    opt = torch.optim.Adam(model.parameters(), lr=lr)
    sched = LearningRateWarmupScheduler(opt, warmup_steps=warmup, total_steps=total)
    all_lrs = []
    for _ in range(total):
        sched.step()
        all_lrs.append(sched.last_lr[0])
    assert sched.global_step == total
    assert all(lr_val >= 0 for lr_val in all_lrs)
